document.addEventListener("DOMContentLoaded",function(){var n=document.querySelector(".create");if(n){n.classList.add("text-end");const t=n.querySelector("a");t&&t.classList.add("btn","btn-primary","m-2")}});document.addEventListener("DOMContentLoaded",function(){var u=document.querySelectorAll(".edit"),n,t,i,r;u.forEach(function(n){n.classList.add("btn","btn-warning","m-2")});n=document.querySelectorAll(".details");n.forEach(function(n){n.classList.add("btn","btn-info","m-2")});t=document.querySelectorAll(".delete");t.forEach(function(n){n.classList.add("btn","btn-danger","m-2")});i=document.querySelectorAll(".add");i.forEach(function(n){n.classList.add("btn","btn-primary","m-2")});r=document.querySelectorAll(".back");r.forEach(function(n){n.classList.add("btn","btn-secondary","m-2")})});